/**
 * main.jsx - React应用的顶层入口文件
 * 
 * 职责：
 * 1. 导入React和ReactDOM相关模块
 * 2. 导入全局样式（Tailwind CSS）
 * 3. 初始化根React应用并挂载到DOM中
 * 
 * 流程：
 * - 获取id为'root'的DOM元素（来自index.html）
 * - 创建React根对象
 * - 在StrictMode包装下渲染App组件（开发环境可检测不安全操作）
 */

import { StrictMode } from 'react'
import { createRoot } from 'react-dom/client'
import './index.css'  // 全局样式：Tailwind CSS + 自定义class
import App from './App.jsx'  // 核心应用路由器组件

// 创建React根对象并渲染
createRoot(document.getElementById('root')).render(
  <StrictMode>
    {/* App是全局路由器，负责管理所有页面状态切换 */}
    <App />
  </StrictMode>,
)
